INSERT INTO public.questions VALUES ('ea94ac68-9e0b-4506-aa1d-78acc04a6c29', 'b67a0d01-5a34-42ad-8682-c71648f11530', 'matching', 'Questions 11-17', '', '<p dir="ltr">Label the map below.</p>
<p dir="ltr">Choose <strong>SEVEN</strong> answers from the box and write the correct letter, <strong>A-H</strong>,next to questions 11-17</p>
<p> </p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p> </p>\n<table style=\"border-collapse: collapse; width: 89.6801%;\" border=\"1\"><colgroup><col style=\"width: 97.7636%;\"><col style=\"width: 2.25484%;\"></colgroup>\n<tbody>\n<tr>\n<td><img src=\"data:image/png;base64,\" width=\"593\" height=\"335\"></td>\n<td>\n<p>{F Local Heroes}</p>\n<p> </p>\n<p>{H Recent Award Winners}</p>\n<p> </p>\n<p>{E Learning Zone}</p>\n<p> </p>\n<p>{G Members'' Restaurant}</p>\n<p> </p>\n<p>{C Gallery Shop}</p>\n<p> </p>\n<p>{D History in Photographs}</p>\n<p> </p>\n<p>{A Cinema Zone}</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p> </p>", "answerOptions": [{"optionText": "A Cinema Zone"}, {"optionText": "B European Paintings"}, {"optionText": "C Gallery Shop"}, {"optionText": "D History in Photographs"}, {"optionText": "E Learning Zone"}, {"optionText": "F Local Heroes"}, {"optionText": "G Members'' Restaurant"}, {"optionText": "H Recent Award Winners"}], "matchingItems": []}', 'null', '[{"content": "<h3 data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">PART 2: MODERN ART GALLERY TOUR</strong></h3>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Guide:</strong> Welcome to the Modern Art Gallery. It is my pleasure to introduce you to the various sections of the gallery. The gallery consists of two levels. As you can see from the map, we are in the large atrium on level 1 at the meeting point.</p>\n<p data-path-to-node=\"5\">First of all, I''ll tell you about the exhibits on this level. In this room <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"5\" data-index-in-node=\"75\">(Q11)</strong></span>, you will find an exhibition of our very own <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"5\" data-index-in-node=\"126\">Local Heroes (F)</strong></span>, told in photographs, paintings and memorabilia. This is a great starting point if you want to find out more about the people who have played an important role in our city.</p>\n<p data-path-to-node=\"6\">Between the ticket booth and lifts, you''ll find the entrance to the other major display on this level <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"6\" data-index-in-node=\"102\">(Q12)</strong></span>. All the works featured here are by <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"6\" data-index-in-node=\"144\">Recent Award Winners (H)</strong></span>—modern artists who have won awards in the last few years. Recent winners such as Martelli and Kashiwagi are on display, and I suggest you take advantage of it while it''s here.</p>\n<p data-path-to-node=\"7\">If you like sculpture, then please visit our section called Latin America. In the far corner, there''s an excellent collection of two of Columbia''s finest: sculptures by Morales and Alvarez are really not to be missed.</p>\n<p data-path-to-node=\"8\">One of my favourite areas on the first level is for our younger visitors. The resident art teacher is here throughout the school holidays to help your children create a piece of art in the <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"8\" data-index-in-node=\"189\">(Q13) Learning Zone (E)</strong></span>. You''ll find it between the Latin American exhibition and the cafe.</p>\n<p data-path-to-node=\"9\">On the right here you''ll find the Gallery Cafe, which serves drinks and light meals throughout the day. If you have membership at any of the galleries or museums in the city, you can make use of the section reserved for members just next door <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"9\" data-index-in-node=\"243\">(Q14)</strong></span>, our <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"9\" data-index-in-node=\"254\">Members'' Restaurant (G)</strong></span>, which has views of the lake and an excellent menu.</p>\n<p data-path-to-node=\"10\">Before you make your way to the second level, you might like to take a look at the books and prints on sale in the <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"10\" data-index-in-node=\"115\">(Q15) Gallery Shop (C)</strong></span>, located next to the information desk. Gift certificates and membership packages can be bought there.</p>\n<p data-path-to-node=\"11\">Now let me introduce the second level of the gallery. As you step out of the lifts, you come into the largest exhibition in the gallery <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"11\" data-index-in-node=\"136\">(Q16)</strong></span>. From World War 1 to the present day, this exhibition, <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"11\" data-index-in-node=\"197\">History in Photographs (D)</strong></span>, shows how photographers have responded to some of the most important local and global events in history.</p>\n<p data-path-to-node=\"12\">On the other side of the lifts is another permanent exhibition called Asia Today. Divided by region, you will experience work from the best Asian artists. And last but not least is one of the most innovative areas of the gallery <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"12\" data-index-in-node=\"229\">(Q17)</strong></span>: our permanent <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"12\" data-index-in-node=\"250\">Cinema Zone (A)</strong></span>. This cinema has two theatres showing films every two hours throughout the day.This month, we feature European filmmakers in the genre of animation from the millennium year to the present day.</p>\n<hr data-path-to-node=\"13\">\n<h3 data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">MUSEUM PASSES (Questions 18–20)</strong></h3>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Guide:</strong> If you have a full day to spend, there are several excellent museums in the city. In the same complex as this gallery, you''ll find the Natural History Museum, which has an excellent collection of gemstones. For those of you with children though, <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"15\" data-index-in-node=\"205\">(Q18) the best option is the recently upgraded Science Centre (A)</strong></span>, just next door to the Maritime Museum on the quayside.</p>\n<p data-path-to-node=\"16\">If you are here with the family and you do intend to visit more than one museum, I definitely recommend purchasing the Family Pass, as this will work out much cheaper and is a really good deal. You can visit two museums in one day, <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"16\" data-index-in-node=\"170\">(Q19) providing there is an adult in the group with between two and four children under sixteen (B - one adult and two children)</strong></span>.</p>\n<p data-path-to-node=\"17\">If you were here for a week or so and you would like to visit several museums or galleries, you might consider the Culture Pass. This allows unlimited entry for two adults to all galleries for <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"17\" data-index-in-node=\"193\">(Q20) three days (B)</strong></span>.</p>\n<p>You will save a lot by doing this, and you could revisit any of the galleries if you like. It''s also really good value as it covers travel on the routes between the museums on weekdays as well as the entry fee, so you save on transport too.</p>\n<p>We hope you enjoy your visit today and continue to support us. If you have any questions...</p>"}]', 0);
INSERT INTO public.questions VALUES ('ee361c31-d06d-49d4-9f10-e578f43ff38e', '57ece189-00b1-4012-b0fd-d77735bc7f26', 'checkbox', 'Questions 25–26', '', '<p data-start="675" data-end="703">Choose <strong data-start="682" data-end="702">TWO letters, A–E</strong>.</p>
<p data-start="705" data-end="801">Which <strong data-start="711" data-end="718">TWO</strong> opinions do both the students express about the evolutionary theory of loneliness?</p>
<p data-start="803" data-end="971" data-is-last-node="" data-is-only-node=""> </p>', 'multiple_choice', 'null', '[{"correct": true, "option_text": "A It has little practical relevance"}, {"correct": true, "option_text": "B It needs further investigation"}, {"correct": false, "option_text": "C It is misleading"}, {"correct": false, "option_text": "D It should be more widely accepted"}, {"correct": false, "option_text": "E It is difficult to understand"}]', 'null', 'null', '[{"content": "<p>1</p>"}]', 2);
INSERT INTO public.questions VALUES ('690880bd-c4fc-446c-a71e-02eb29b86680', 'b7ede2b9-71ed-42de-aa36-4ae92d763294', 'radio', 'Questions 1–4', NULL, '<p>Choose <strong>TRUE </strong>if the statement agrees with the information  <strong>FALSE </strong>if the statement contradicts the information  <strong>NOT GIVEN </strong>if there is no information on this</p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "TRUE "}, {"content": "FALSE "}, {"content": "NOT GIVEN "}], "question": "Research to date has concentrated on the importance of escape speed in surviving an attack by a predator"}, {"correct": 0, "options": [{"content": "TRUE "}, {"content": "FALSE "}, {"content": "NOT GIVEN "}], "question": "According to the ''bigger is better'' hypothesis, larger animals have better eyesight"}, {"correct": 1, "options": [{"content": "TRUE "}, {"content": "FALSE "}, {"content": "NOT GIVEN "}], "question": "Early-juvenile reef fish share similar characteristics"}, {"correct": 2, "options": [{"content": "TRUE "}, {"content": "FALSE "}, {"content": "NOT GIVEN "}], "question": "Fully developed reef fish have a slower swimming speed than juveniles"}]', 'null', 'null', 'null', '[{"content": "<p>1. Research to date has concentrated on the importance of escape speed in surviving an attack by a predator.</p>\n<ul>\n<li>\n<p><strong class=\"\">Đáp án:</strong> <strong class=\"\">FALSE</strong></p>\n</li>\n<li>\n<p><strong class=\"\">Dẫn chứng:</strong><span class=\"\"> (Đoạn 1) &#8220;Body size,</span><span class=\"\"> weight,</span><span class=\"\"> growth rate,</span><span class=\"\"> overall condition,</span><span class=\"\"> sensory development and </span><strong class=\"\">escape speed</strong><span class=\"\"> have all been linked to survival.</span> <strong class=\"\">Of these, body size has received the most attention</strong><span class=\"\"> from researchers&#8230;</span><span class=\"\">&#8220;</span></p>\n</li>\n<li>\n<p><strong class=\"\">Giải thích:</strong><span class=\"\"> Văn bản liệt kê nhiều yếu tố,</span><span class=\"\"> bao gồm tốc độ trốn thoát,</span><span class=\"\"> nhưng khẳng định </span><strong class=\"\">kích thước cơ thể</strong><span class=\"\"> (body size) mới là yếu tố được tập trung nghiên cứu nhiều nhất (&#8220;most attention&#8221;).</span></p>\n</li>\n</ul>\n<p> </p>\n<p>2. According to the &#8216;bigger is better&#8217; hypothesis, larger animals have better eyesight.</p>\n<ul>\n<li>\n<p><strong class=\"\">Đáp án:</strong> <strong class=\"\">TRUE</strong></p>\n</li>\n<li>\n<p><strong class=\"\">Dẫn chứng:</strong><span class=\"\"> (Đoạn 1) &#8220;This theory predicts that larger body size should increase an individual&#8217;s ability to escape from a predator due to the characteristics associated with this,</span><span class=\"\"> such as overall strength and </span><strong class=\"\">visual development</strong><span class=\"\">.</span><span class=\"\">&#8220;</span></p>\n</li>\n<li>\n<p><strong class=\"\">Giải thích:</strong><span class=\"\"> &#8220;Visual development&#8221; (sự phát triển thị giác) đồng nghĩa với việc có thị lực/thị giác tốt hơn (better eyesight).</span></p>\n</li>\n</ul>\n<p> </p>\n<p>3. Early-juvenile reef fish share similar characteristics.</p>\n<ul>\n<li>\n<p><strong class=\"\">Đáp án:</strong> <strong class=\"\">FALSE</strong></p>\n</li>\n<li>\n<p><strong class=\"\">Dẫn chứng:</strong><span class=\"\"> (Đoạn 2) &#8220;&#8230;</span><span class=\"\">determine whether a predator&#8217;s choice of prey is influenced by factors such as the prey&#8217;s size,</span><span class=\"\"> weight and swimming speed,</span><span class=\"\"> as these characteristics </span><strong class=\"\">vary from individual to individual</strong><span class=\"\"> at the beginning of the juvenile stage.</span><span class=\"\">&#8220;</span></p>\n</li>\n<li>\n<p><strong class=\"\">Giải thích:</strong><span class=\"\"> Các đặc điểm của cá non </span><strong class=\"\">khác nhau</strong><span class=\"\"> giữa các cá thể (&#8220;vary from individual to individual&#8221;),</span> mâu thuẫn với việc chúng &#8220;share similar characteristics&#8221; (chia sẻ các đặc điểm tương tự).</p>\n</li>\n</ul>\n<p> </p>\n<p>4. Fully developed reef fish have a slower swimming speed than juveniles.</p>\n<ul>\n<li>\n<p><strong>Đáp án:</strong> <strong>NOT GIVEN</strong></p>\n</li>\n<li>\n<p><strong>Dẫn chứng:</strong> Văn bản chỉ nói về cá ấu trùng và cá non, và đề cập đến việc cá lớn hơn không nhất thiết bơi nhanh hơn cá nhỏ hơn (Đoạn 8).</p>\n</li>\n<li>\n<p><strong>Giải thích:</strong> <strong>Không có thông tin</strong> so sánh trực tiếp tốc độ bơi giữa cá trưởng thành hoàn toàn (&#8220;fully developed reef fish&#8221; / &#8220;adult&#8221;) và cá non (&#8220;juveniles&#8221;).</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('e92705c2-2940-419d-8a84-c2f2bac06ec7', '57ece189-00b1-4012-b0fd-d77735bc7f26', 'radio', 'Questions 27–30', '', NULL, 'multiple_choice', '[{"correct": 0, "options": [{"option_text": "A doubt that there will ever be a medical cure for loneliness"}, {"option_text": "B claim that the link between loneliness and mental health is overstated"}, {"option_text": "C express frustration that loneliness is not taken more seriously"}], "question": "Choose the correct letter, A, B or C.  Loneliness and mental health"}, {"correct": 1, "options": [{"option_text": "A to explain how difficult loneliness can be"}, {"option_text": "B to highlight a situation that most students will recognise"}, {"option_text": "C to emphasise that feeling lonely is more common for men than women"}], "question": "Why do the students decide to start their presentation with an example from their own experience?"}, {"correct": 0, "options": [{"option_text": "A it creates a sense of belonging"}, {"option_text": "B it builds self-confidence"}, {"option_text": "C it makes people feel more positive"}], "question": "The students agree that talking to strangers is a good strategy for dealing with loneliness because"}, {"correct": 2, "options": [{"option_text": "A similar to loneliness"}, {"option_text": "B necessary for mental health"}, {"option_text": "C an enjoyable experience"}], "question": ""}]', 'null', 'null', 'null', '[{"content": "<p>1</p>"}]', 3);
INSERT INTO public.questions VALUES ('3f7376d9-fb18-4230-a606-0cc92dd19677', 'a8b7ca66-6a01-4512-bf65-b80ea2cb843c', 'fillup', 'Questions 31–40', '<p data-start="109" data-end="177">Write <strong data-start="143" data-end="160">ONE WORD ONLY</strong> for each answer.</p>
<div class="flex max-w-full flex-col grow">
<div class="min-h-8 text-message relative flex w-full flex-col items-end gap-2 text-start break-words whitespace-normal [.text-message+&amp;]:mt-1" dir="auto" data-message-author-role="assistant" data-message-id="3579930b-3009-46eb-8c45-70f541311098" data-message-model-slug="gpt-5-2">
<div class="flex w-full flex-col gap-1 empty:hidden first:pt-[1px]">
<div class="markdown prose dark:prose-invert w-full wrap-break-word light markdown-new-styling">
<p style="text-align: center;" data-start="184" data-end="214"><span style="font-size: 14pt;"><strong data-start="187" data-end="214">Reclaiming urban rivers</strong></span></p>
<p data-start="216" data-end="245"><strong data-start="220" data-end="245">Historical background</strong></p>
<ul data-start="246" data-end="646">
<li data-start="246" data-end="296">
<p data-start="248" data-end="296">Nearly all major cities were built on a river.</p>
</li>
<li data-start="297" data-end="387">
<p data-start="299" data-end="387">Rivers were traditionally used by city dwellers for transport, fishing and recreation.</p>
</li>
<li data-start="388" data-end="567">
<p data-start="390" data-end="567">Industrial development and rising populations later led to:<br data-start="449" data-end="452">– more sewage from houses being discharged into the river<br data-start="511" data-end="514">– pollution from <strong data-start="533" data-end="546">{factories}</strong> on the river bank.</p>
</li>
<li data-start="568" data-end="646">
<p data-start="570" data-end="646">In 1957, the River Thames in London was declared biologically <strong data-start="632" data-end="645">{dead}</strong>.</p>
</li>
</ul>
<p data-start="648" data-end="675"><strong data-start="652" data-end="675">Recent improvements</strong></p>
<ul data-start="676" data-end="1014">
<li data-start="676" data-end="746">
<p data-start="678" data-end="746">Seals and even a <strong data-start="695" data-end="708">{whale}</strong> have been seen in the River Thames.</p>
</li>
<li data-start="747" data-end="819">
<p data-start="749" data-end="819">Riverside warehouses are converted to restaurants and <strong data-start="803" data-end="816">{apartments}</strong>.</p>
</li>
<li data-start="820" data-end="936">
<p data-start="822" data-end="936">In Los Angeles, there are plans to:<br data-start="857" data-end="860">– build a riverside <strong data-start="882" data-end="895">{park}</strong>.<br data-start="896" data-end="899">– display <strong data-start="911" data-end="924">{art}</strong> projects.</p>
</li>
<li data-start="937" data-end="1014">
<p data-start="939" data-end="1014">In Paris, <strong data-start="949" data-end="962">{beaches}</strong> are created on the sides of the river every summer.</p>
</li>
</ul>
<p data-start="1016" data-end="1047"><strong data-start="1020" data-end="1047">Transport possibilities</strong></p>
<ul data-start="1048" data-end="1367" data-is-last-node="" data-is-only-node="">
<li data-start="1048" data-end="1136">
<p data-start="1050" data-end="1136">Over 2 billion passengers already travel by <strong data-start="1094" data-end="1107">{ferry}</strong> in cities round the world.</p>
</li>
<li data-start="1137" data-end="1226">
<p data-start="1139" data-end="1226">Changes in shopping habits mean the number of deliveries that are made is increasing.</p>
</li>
<li data-start="1227" data-end="1367" data-is-last-node="">
<p data-start="1229" data-end="1367" data-is-last-node="">Instead of road transport, goods could be transported by large freight barges and electric <strong data-start="1320" data-end="1333">{bikes}</strong>, or, in future, by <strong data-start="1353" data-end="1366">{drone}</strong>.</p>
</li>
</ul>
</div>
</div>
</div>
</div>
<div class="z-0 flex min-h-[46px] justify-start"> </div>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">PART 4 – CITY RIVERS</strong></p>\n<p data-path-to-node=\"3\">It’s quite hard to think of a city that doesn’t have a big river running through it. If you think about the major cities in the world, Shanghai, New York, Mumbai, London, they’re nearly all built on rivers.</p>\n<p data-path-to-node=\"4\">When these cities were established hundreds or even thousands of years ago, the rivers were a big part of people’s lives. In 16th-century London, the quickest way to get from one part of the city to another was by river. But people also used the river for fishing, as the water then was relatively clean, and they would also go on boat trips up and down the river just for pleasure, as a relaxing escape from the noise and bustle of the city streets.</p>\n<p data-path-to-node=\"5\">But as industries developed and populations increased, city rivers suffered. The rising number of people meant there was a huge increase in the amount of sewage discharged into the rivers. Rivers had always been used for this purpose, but when the number of inhabitants was so small that wasn’t such a problem. However, as cities grew to over a million inhabitants, the impact on the rivers became more serious. In addition, other types of pollution increased as <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"5\" data-index-in-node=\"463\">factories</strong> (Q31)</span> were built beside the river and discharged their waste materials into the water. This got worse over time. As recently as 1957, scientists at London’s Natural History Museum declared that the River Thames was <strong data-path-to-node=\"5\" data-index-in-node=\"688\">‘<span style=\"background-color: #f3db7b;\">dead</span>’</strong> (Q32) in biological terms, as the water was too filthy to support any kind of life.</p>\n<p data-path-to-node=\"6\">But in recent years, as rivers lost their industrial function, cities have begun to recognise their true value and to take steps to clean them up. For example, the River Thames is now cleaner than it’s been for a hundred and fifty years. These days you can see seals swimming in the water and recently people had to try to rescue a <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"6\" data-index-in-node=\"332\">whale</strong> </span>(Q33) which had got lost and swum up the river from the sea by mistake. Unfortunately they didn’t succeed, but the problem was disorientation rather than the quality of the water.</p>\n<p data-path-to-node=\"7\">Then, all around the world, riverside areas are now seen as prime sites for development. Warehouses that were once used for storing goods are now being converted into expensive restaurants and also into <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"7\" data-index-in-node=\"203\">apartments</strong> </span>(Q34) with river views, which are in great demand and sell for astronomical prices.</p>\n<p data-path-to-node=\"8\">In Los Angeles, on the west coast of the USA, an architect has plans to revitalise the banks of the river and to make a <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"8\" data-index-in-node=\"120\">park</strong> </span>(Q35) there which can provide facilities for sports as well as a natural environment for relaxing in. It’s also hoped that the riverside can be used for other purposes – it’s been proposed that facilities could be provided for displaying projects related to various kinds of <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"8\" data-index-in-node=\"400\">art</strong> </span>(Q36) that have been produced by local people, for example.</p>\n<p data-path-to-node=\"9\">In the city of Paris, during the summer months of July and August, all the traffic is banned from the roads by the sides of the river and the banks are transformed into <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"9\" data-index-in-node=\"169\">beaches</strong> </span>(Q37), where people can relax in deckchairs under potted palm trees, sunbathe, or buy a drink or a snack while enjoying the view.</p>\n<hr data-path-to-node=\"10\">\n<p data-path-to-node=\"11\">But to make the most of our rivers in our increasingly crowded cities, we need to allow them to regain their original purpose and be used as a means of transport, reclaiming our streets from cars and lorries. To do this we’ll have to shift more traffic back to the river, but this time cleanly and silently, making the most of modern technology. Already more than two billion passengers use the <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"11\" data-index-in-node=\"395\">ferry</strong> </span>(Q38) to travel in cities around the world like Istanbul, San Francisco and New York. And these numbers are set to rise further. Admittedly, it’s not a fast way of travelling, but neither is a car when it’s stuck in traffic.</p>\n<p data-path-to-node=\"12\">Of course, passenger traffic on roads might decrease as more people start working from home. But another recent development, the huge rise in online shopping, has meant that another form of urban traffic just keeps on growing, and that’s deliveries. Trucks and vans in the city pollute and double park while dropping off parcels. Imagine using the immense capacity of shipping to take these trucks off the road. One freight barge can replace 44 large trucks, uses far less energy and causes less pollution. When the barge docks at the riverside, the parcels could be taken the last few kilometres to their final destination on cargo <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"12\" data-index-in-node=\"633\">bikes</strong> </span>(Q39) – electric ones, of course. This is already happening in the Dutch city of Amsterdam. And in future, the final stage could even be carried out by <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"12\" data-index-in-node=\"791\">drone</strong> </span>(Q40), although at present this isn’t allowed. Wouldn’t it be great to unblock our city centres in this way!</p>\n<p data-path-to-node=\"13\">Looking further ahead …</p>"}]', 0);
INSERT INTO public.questions VALUES ('d3a440ae-01c3-4d9f-9863-e23dd2246833', 'c8d26b3b-8b1d-4c44-9f4d-19f1947ec1ec', 'radio', 'Questions 11–14', NULL, '<p>Choose the correct answer.</p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "A.are given a litte money."}, {"content": "B.do not receive payment."}, {"content": "C.can apply for expenses."}], "question": "People who act as hosts for Connections"}, {"correct": 0, "options": [{"content": "A.have difficulty making friends."}, {"content": "B.are looking for temporary work."}, {"content": "C.can offer language support."}], "question": "Connections is for people from other countries who"}, {"correct": 2, "options": [{"content": "A.cook food for their host family"}, {"content": "B.explain their own family traditions."}, {"content": "C.discuss matters of personal interest."}], "question": "According to the speaker, what can a guest expect to do during their stay?"}, {"correct": 0, "options": [{"content": "A.an increased understanding between cultures."}, {"content": "B.a programme of weekly visits."}, {"content": "C.more involvement from people of different communities."}], "question": "According to the speaker, a long-term benefit of the Connections scheme could be"}]', 'null', 'null', 'null', '[{"content": "<h2>(Section 2)</h2>\n<p>Hello listeners. To this program will know that we’re very keen to foster links within communities, and we think we’ve hit on a winning idea. I’m going to tell you about a scheme which has been set up as part of our Communities in Action program for those who’d like to be put in touch with people from different countries and cultures.</p>\n<p>As the name Connections suggests, we’re hoping that the scheme will introduce people who live in this country who will act as hosts to people who’ve recently arrived here to study or to work for a limited period of time, who will be their guests.</p>\n<p>Now if you’ve got a spare room in your house or flat, you might like to be a host and have someone stay for a weekend. I should point out that no money is involved as all our hosts are <strong>(11) unpaid (B)</strong>. But you should not have too much extra expense other than one more person joining you at mealtimes.</p>\n<p>In the course of their studies or work in this country, some people rarely get the opportunity to socialize. There may be language problems or feelings of shyness, which mean that whatever their age, people can become quite <strong>lonely or isolated (A)</strong>. If you are prepared to invite someone into your home, you can rely on Connections for a personal introduction, and the timing of the invitation will be to suit you, as I said, the stay is always over a weekend for two or three nights, and as the host, the arrangements you make for your visitor will depend on your other commitments.</p>\n<p>If you’re listening to this program and you would like to take advantage of what Connections can offer a guest, then what I’m going on to say will apply to you. So what will you, the guest, get out of a visit? You’ll gain an insight into the customs and way of life of the country you’re staying in and you’ll enjoy home cooked meals, and be able to <strong>(13) ask questions about things which interest you or perhaps even puzzle you (C)</strong>.</p>\n<p>It’s early days, but if a weekend stay goes well, relationships might develop over time and turn into lasting and genuine friendships. This would undoubtedly be of advantage to the whole community, as we all become more <strong>(14) aware of the ways in which people in different countries live their lives (A)</strong>. There’s also the possibility that when you return to your own country, you might one day want to invite your hosts to stay with you.</p>\n<p> </p>\n<p>  Right, I hope I’ve given you enough information on the scheme and what we’re setting out to do. I’ll now deal with the process for applying, if you’d like to be involved from the point of view of a guest. So have a pencil and some paper ready to jot down what you need to do.</p>\n<p>Connections is broken up into various small sections which will deal with your application through the different stages. To begin with, we ask you to make a phone call to our <strong>(15) vetting (H)</strong> people. We need to know some basic information about you, like how long you’re intending to be in this country, the minimum time limit is 3 months, whether you’re working or studying.</p>\n<p>We require a reference, which must be from the person in authority who you’re working with or studying under. This will be used for an <strong>(16) identity (C)</strong> check. Once that’s been sent to the authorities and approved, we’ll email you an application form which you can download.</p>\n<p>You should complete this and return it with two recent passport sized photographs of yourself. One photo will be held in our <strong>(17) records (F)</strong> and the other will be sent to your host family prior to your first weekend visit.</p>\n<p>Our Centre Manager will get back to you within a week of receiving your form to let you know that we have it <strong>(18) (A: Acknowledgement)</strong>. And if we think there’s a suitable match on our files, someone from our interview team will contact you for a face to face meeting with a member of staff <strong>(19) (D: An interview)</strong>. At that point, you should have some idea of weekend dates when you’re free, which we can put to the host family.</p>\n<p>However, decisions are not made at the meeting, but you can expect to hear the <strong>(20) result (B: Decision)</strong> from us in a couple of days. Now the process for those of you interested in welcoming someone…</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('d9ba649c-6d3c-4ae1-85cf-4eabe55e72a2', 'c8d26b3b-8b1d-4c44-9f4d-19f1947ec1ec', 'matching', 'Questions 15–20', NULL, '<p>Complete the fow – chart below.</p>
<p>Choose <strong>SIX</strong> correct answers, <strong>A</strong>–<strong>H</strong>, next to questions 15 – 20.</p>', 'matching_features', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p class=\"MsoNormal\" style=\"text-align: center; background: white;\" align=\"center\"><span style=\"font-size: 12pt;\"><strong><span lang=\"vi\" style=\"line-height: 115%; font-family: Calibri, sans-serif; color: #15191e;\">To apply to <em style=\"mso-bidi-font-style: normal;\">Connections</em> as a guest</span></strong></span></p>\n<p class=\"MsoNormal\" style=\"text-align: center; background: white; line-height: 1;\" align=\"center\"><span style=\"font-size: 12pt;\"><span lang=\"vi\" style=\"line-height: 115%; font-family: Calibri, sans-serif; color: black;\">The applicant makes an initial phone call to the {Vetting}</span><span lang=\"vi\" style=\"line-height: 115%; font-family: Calibri, sans-serif; color: #15191e;\"> department.</span></span></p>\n<p style=\"text-align: center;\">⬇</p>\n<p class=\"MsoNormal\" style=\"text-align: center; background: white; line-height: 1;\" align=\"center\"><span style=\"font-size: 12pt;\"><span lang=\"vi\" style=\"line-height: 115%; font-family: Calibri, sans-serif; color: black;\">The applicant sends in a reference to confirm his/her {Identity}</span><span lang=\"vi\" style=\"line-height: 115%; font-family: Calibri, sans-serif; color: #15191e;\"> .</span></span></p>\n<p style=\"text-align: center;\">⬇</p>\n<p class=\"MsoNormal\" style=\"text-align: center; background: white; line-height: 1;\" align=\"center\"><span lang=\"vi\" style=\"font-size: 12pt; line-height: 115%; font-family: Calibri, sans-serif; color: black;\">Following approval, an application form is emailed to the applicant.</span></p>\n<p style=\"text-align: center;\">⬇</p>\n<p class=\"MsoNormal\" style=\"text-align: center; background: white; line-height: 1;\" align=\"center\"><span style=\"font-size: 12pt;\"><span lang=\"vi\" style=\"line-height: 115%; font-family: Calibri, sans-serif; color: black;\">The applicant returns the completed form with two photographs (one for </span><span lang=\"vi\" style=\"line-height: 115%; font-family: Calibri, sans-serif; color: #15191e;\"><span style=\"mso-spacerun: yes;\"> </span>{Records} and one for the family).</span></span></p>\n<p style=\"text-align: center;\">⬇</p>\n<p class=\"MsoNormal\" style=\"text-align: center; background: white; line-height: 1;\" align=\"center\"><span style=\"font-size: 12pt;\"><span lang=\"vi\" style=\"line-height: 115%; font-family: Calibri, sans-serif; color: black;\">The applicant receives {Acknowledgement}</span><span lang=\"vi\" style=\"line-height: 115%; font-family: Calibri, sans-serif; color: #15191e;\"><span style=\"mso-spacerun: yes;\"> </span>within seven days.</span></span></p>\n<p style=\"text-align: center;\">⬇</p>\n<p class=\"MsoNormal\" style=\"text-align: center; background: white; line-height: 1;\" align=\"center\"><span style=\"font-size: 12pt;\"><span lang=\"vi\" style=\"line-height: 115%; font-family: Calibri, sans-serif; color: black;\">The applicant has<span style=\"mso-spacerun: yes;\">  </span>{An interview}</span><span lang=\"vi\" style=\"line-height: 115%; font-family: Calibri, sans-serif; color: #15191e;\"> with a staff member.</span></span></p>\n<p style=\"text-align: center;\">⬇</p>\n<p class=\"MsoNormal\" style=\"text-align: center; background: white; line-height: 1;\" align=\"center\"><span style=\"font-size: 12pt;\"><span lang=\"vi\" style=\"line-height: 115%; font-family: Calibri, sans-serif; color: black;\">The applicant receives a final {Decision} </span><span lang=\"vi\" style=\"line-height: 115%; font-family: Calibri, sans-serif; color: #15191e;\"><span style=\"mso-spacerun: yes;\"> </span>in writing.</span></span></p>", "answerOptions": [{"optionText": "Acknowledgement"}, {"optionText": "Decision"}, {"optionText": "Identity"}, {"optionText": "An interview"}, {"optionText": "Legal status"}, {"optionText": "Records"}, {"optionText": "Rejection"}, {"optionText": "Vetting"}], "matchingItems": null}', 'null', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('17e47165-c638-438d-8d4b-7f00c02b8361', '21a8c315-7f0a-47b9-8c0a-c69c49e7bd08', 'matrix', 'Questions 27–31', NULL, '<p>Reading Passage 3 has eight paragraphs, <strong>A-H</strong>.</p>
<p>Which paragraph contains the following information?</p>
<p>Choose the correct letter, <strong>A-H</strong>, in boxes 27-31.</p>
<p>NB You may use any letter more than once.</p>
', 'other', 'null', 'null', 'null', '{"layoutType": "simple", "legendTitle": null, "matrixItems": [{"itemText": "the part of cocoa trees used for chocolate production", "correctCategoryLetter": "F"}, {"itemText": "annual chocolate consumption per capita in the United States", "correctCategoryLetter": "H"}, {"itemText": "the higher likelihood of cultivated cocoa trees being attacked by insects", "correctCategoryLetter": "F"}, {"itemText": "a community which developed a preference for sweetened chocolate beverages", "correctCategoryLetter": "E"}, {"itemText": "an approach by which ancient Mexicans could acquire cocoa beans", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}]}', '[{"content": "<p data-path-to-node=\"2\"><strong>27. the part of cocoa trees used for chocolate production</strong></p>\n<ul data-path-to-node=\"3\">\n<li>\n<p data-path-to-node=\"3,0,0\"><strong>Đáp án: F</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong>Dẫn chứng:</strong> (Đoạn F) “These pods contain the <strong>beans</strong> used in chocolate production.”</p>\n</li>\n<li>\n<p data-path-to-node=\"3,2,0\"><strong>Giải thích:</strong> Đoạn F mô tả quả (pod) và hạt (<strong>beans</strong>) là bộ phận của cây được dùng để sản xuất sô cô la.</p>\n</li>\n</ul>\n<p data-path-to-node=\"4\"><strong>28. annual chocolate consumption per capita in the United States</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong>Đáp án: H</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong>Dẫn chứng:</strong> (Đoạn H) “<strong>On average, Americans consume over five kilogrammes of chocolate per person each year</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong>Giải thích:</strong> Đoạn H cung cấp số liệu thống kê về mức tiêu thụ sô cô la hàng năm tính trên đầu người (per capita) ở Mỹ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong>29. the higher likelihood of cultivated cocoa trees being attacked by insects</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong>Đáp án: F</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong>Dẫn chứng:</strong> (Đoạn F) “<strong>Unexpectedly, cocoa trees grown on farms are more vulnerable to disease and pests than their wild counterparts</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong>Giải thích:</strong> Đoạn F so sánh khả năng bị bệnh dịch và sâu bệnh (bao gồm côn trùng/insects) của cây trồng (cultivated) so với cây dại (wild counterparts).</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong>30. a community which developed a preference for sweetened chocolate beverages</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong>Đáp án: E</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong>Dẫn chứng:</strong> (Đoạn E) “<strong>Spanish elite first developed a taste for sweetened chocolate drinks</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong>Giải thích:</strong> Đoạn E nói về việc giới tinh hoa Tây Ban Nha (Spanish elite/community) là những người đầu tiên phát triển sở thích uống sô cô la có đường.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong>31. an approach by which ancient Mexicans could acquire cocoa beans</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong>Đáp án: D</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong>Dẫn chứng:</strong> (Đoạn D) “The Aztec civilisation in Mexico… Accordingly, <strong>they sourced cocoa beans through extensive trade networks</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong>Giải thích:</strong> Đoạn D mô tả cách người Aztec (Mexicans) thu mua hạt ca cao thông qua mạng lưới thương mại (trade networks), do không thể tự trồng.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('d752d1e4-8a8b-4bdc-85e0-131b958ae9c3', '4c130452-5493-4e6b-9642-58f08c77449f', 'fillup', 'Questions 1–10', '<div class="flex flex-col text-sm pb-25">
